// // This module maps 2-bit inputs to 3-bit outputs using a case statement. If the input is 00, it outputs 101; if the input is 01, it outputs 001; otherwise, it defaults to 000.
module top_module(in_a, out_vt);input [1:0] in_a;
output out_vt;
reg   [2:0] result;
assign out_vt = result;

always @(*)
  begin
     result    = 3'b000;
     case (in_a)
       2'b00 : begin
          result = 3'b101;
       end

       2'b01: begin
          result    = 3'b001;
       end

       default;

     endcase
  end
endmodule
